import React, { Component } from "react";
import "./AddSaveButtonTransporte.css";

class AddSaveButtonTransporte extends Component {
  state = {
    name: this.props.name,
    theme: this.props.theme,

    addSaveButtonProduct: this.props.addSaveButtonProduct,
  };

  render() {
    var theme = styleButtonColors.dark;

    if (this.state.theme == "light") {
      theme = styleButtonColors.light;
    }

    const name = this.state.name;

    return (
      <button className="addSaveButtonProduct" style={theme}
      onClick={() => {
        this.state.addSaveButtonProduct();
      }}>
        {name}
      </button>
    );
  }
}

const styleButtonColors = {
  dark: {
    border: "1px solid black",
    color: "black",
  },
  light: {
    border: "1px solid rgb(164, 164, 164)",
    color: "white",
  },
};

export default AddSaveButtonTransporte;
